/**
 * 24h compliance evaluator for BESS metrics (from Google Sheets).
 * Outputs violation intervals (start -> resolved) instead of per-timestamp events.
 * Adds rounding + compact display fields.
 * Spread violations: collects ALL involved IDs across the interval (instead of ID max/min).
 *
 * DST-safe for Europe/Prague (handles CET/CEST automatically).
 */

// ---------- CONFIG ----------
const COL = {
  time: "time",

  cellVmin: "cell_voltage_min_v_avg",
  cellVmax: "cell_voltage_max_v_avg",
  modVmin:  "module_voltage_min_v_avg",
  modVmax:  "module_voltage_max_v_avg",

  cellTmin: "cell_temp_min_c_avg",
  cellTmax: "cell_temp_max_c_avg",
  modTmin:  "module_temp_min_c_avg",
  modTmax:  "module_temp_max_c_avg",

  soc: "soc_pct_avg",

  cellIdMaxT: "cell_id_max_temp_avg",
  cellIdMinT: "cell_id_min_temp_avg",
  modIdMaxT:  "module_id_max_temp_avg",
  modIdMinT:  "module_id_min_temp_avg",

  cellIdMaxV: "cell_id_max_voltage_avg",
  cellIdMinV: "cell_id_min_voltage_avg",
  modIdMaxV:  "module_id_max_voltage_avg",
  modIdMinV:  "module_id_min_voltage_avg",
};

const LIMITS = {
  cellTemp: { min: 0, max: 50, unit: "°C" },
  modTemp:  { min: 0, max: 50, unit: "°C" },
  soc:      { min: 8, max: 98, unit: "%" },
  cellVolt: { min: 3, max: 3.6, unit: "V" },

  cellTempSpreadMax: 5,
  modTempSpreadMax:  5,

  moduleVoltSpreadMax: 0.3,
  cellVoltSpreadMax:   0.03,
};

const TIMEZONE = "Europe/Prague";

// ---------- helpers ----------
const toNum = (v) => {
  if (v === null || v === undefined || v === "") return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const toMs = (t) => {
  const ms = Date.parse(t);
  return Number.isFinite(ms) ? ms : null;
};

function pct(n, d) {
  if (!d) return 0;
  return Math.round((n / d) * 10000) / 100;
}

function tallyInc(map, v) {
  const n = toNum(v);
  if (n === null) return;
  const key = String(Math.trunc(n));
  map.set(key, (map.get(key) || 0) + 1);
}

function topShare(map) {
  if (!map.size) return { topId: null, topCount: 0, topPct: 0, total: 0, breakdown: [] };

  let total = 0;
  let topId = null;
  let topCount = -1;

  for (const [k, c] of map.entries()) {
    total += c;
    if (c > topCount) { topCount = c; topId = k; }
  }

  const breakdown = Array.from(map.entries())
    .sort((a,b) => b[1] - a[1])
    .slice(0, 10)
    .map(([id, count]) => ({ id, count, pct: pct(count, total) }));

  return { topId, topCount, topPct: pct(topCount, total), total, breakdown };
}

function minMaxPush(state, v) {
  if (v === null) return;
  if (v < state.min) state.min = v;
  if (v > state.max) state.max = v;
}

function pad2(n){ return String(n).padStart(2, "0"); }
function pad3(n){ return String(n).padStart(3, "0"); }

// ---------- timezone / DST-safe helpers for Europe/Prague ----------
function getTzParts(ms, timeZone = TIMEZONE) {
  const d = new Date(ms);
  const dtf = new Intl.DateTimeFormat("en-CA", {
    timeZone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hourCycle: "h23",
  });

  const parts = dtf.formatToParts(d);
  const obj = {};
  for (const p of parts) {
    if (p.type !== "literal") obj[p.type] = p.value;
  }

  return {
    year: Number(obj.year),
    month: Number(obj.month),
    day: Number(obj.day),
    hour: Number(obj.hour),
    minute: Number(obj.minute),
    second: Number(obj.second),
  };
}

function ymdInPrague(dateNow = new Date()) {
  const p = getTzParts(dateNow.getTime(), TIMEZONE);
  return `${p.year}-${pad2(p.month)}-${pad2(p.day)}`;
}

/**
 * Returns timezone offset in milliseconds for given UTC timestamp in target zone.
 * Example: Prague winter -> +3600000, summer -> +7200000
 */
function getOffsetMs(ms, timeZone = TIMEZONE) {
  const p = getTzParts(ms, timeZone);
  const utcEquivalent = Date.UTC(
    p.year,
    p.month - 1,
    p.day,
    p.hour,
    p.minute,
    p.second,
    0
  );
  return utcEquivalent - ms;
}

/**
 * Converts local wall-clock datetime in Europe/Prague to UTC ms.
 * Handles DST automatically.
 */
function zonedDateTimeToUtcMs(year, month, day, hour = 0, minute = 0, second = 0, ms = 0, timeZone = TIMEZONE) {
  // initial guess as if local time were UTC
  let guess = Date.UTC(year, month - 1, day, hour, minute, second, ms);

  // refine with timezone offset at guessed instant
  let offset = getOffsetMs(guess, timeZone);
  let result = Date.UTC(year, month - 1, day, hour, minute, second, ms) - offset;

  // second pass for DST boundary correctness
  const offset2 = getOffsetMs(result, timeZone);
  if (offset2 !== offset) {
    result = Date.UTC(year, month - 1, day, hour, minute, second, ms) - offset2;
  }

  return result;
}

function makePragueMidnightMs(ymd) {
  const [y, m, d] = ymd.split("-").map(Number);
  return zonedDateTimeToUtcMs(y, m, d, 0, 0, 0, 0, TIMEZONE);
}

function formatOffset(offsetMs) {
  const sign = offsetMs >= 0 ? "+" : "-";
  const abs = Math.abs(offsetMs);
  const hh = pad2(Math.floor(abs / 3600000));
  const mm = pad2(Math.floor((abs % 3600000) / 60000));
  return `${sign}${hh}:${mm}`;
}

function formatPrague(ms) {
  const p = getTzParts(ms, TIMEZONE);
  const d = new Date(ms);
  const milli = pad3(d.getUTCMilliseconds());
  const offset = formatOffset(getOffsetMs(ms, TIMEZONE));

  return `${p.year}-${pad2(p.month)}-${pad2(p.day)}T${pad2(p.hour)}:${pad2(p.minute)}:${pad2(p.second)}.${milli}${offset}`;
}

// duration ms -> hh:mm:ss
function formatDuration(ms) {
  if (ms === null || ms === undefined || !Number.isFinite(ms) || ms < 0) return "";
  const totalSec = Math.round(ms / 1000);
  const h = Math.floor(totalSec / 3600);
  const m = Math.floor((totalSec % 3600) / 60);
  const s = totalSec % 60;
  return `${pad2(h)}:${pad2(m)}:${pad2(s)}`;
}

// ---------- rounding + formatting (for PDF stability) ----------
function roundTo(v, d){
  if (v === null || v === undefined || !Number.isFinite(v)) return null;
  const p = 10 ** d;
  return Math.round(v * p) / p;
}

function decimalsFor(unit, metric){
  if (unit === "V") {
    if (String(metric).includes("spread")) return 4;
    return 3;
  }
  if (unit === "°C") return 1;
  if (unit === "%") return 1;
  return 3;
}

function fmt(v, d){
  if (v === null || v === undefined || !Number.isFinite(v)) return "";
  return roundTo(v, d).toFixed(d);
}

function fmtSmart(v, unit, metric){
  const d = decimalsFor(unit, metric);
  return fmt(v, d);
}

function fmtRule(rule, unit, metric){
  if (!rule) return "";
  const u = rule.unit || unit || "";
  const d = decimalsFor(u, metric);
  if (rule.min !== undefined && rule.max !== undefined) {
    return `${fmt(rule.min, d)}–${fmt(rule.max, d)} ${u}`.trim();
  }
  if (rule.max !== undefined) {
    return `≤ ${fmt(rule.max, d)} ${u}`.trim();
  }
  return `${JSON.stringify(rule)}`;
}

/**
 * Spread-ID list formatting (compact, capped).
 */
function fmtIds(idsArr, cap = 12) {
  const ids = (idsArr || [])
    .map(x => String(x).trim())
    .filter(x => x.length > 0);

  if (!ids.length) return "";

  ids.sort((a,b) => {
    const na = Number(a), nb = Number(b);
    const fa = Number.isFinite(na), fb = Number.isFinite(nb);
    if (fa && fb) return na - nb;
    if (fa && !fb) return -1;
    if (!fa && fb) return 1;
    return a.localeCompare(b);
  });

  const shown = ids.slice(0, cap);
  const rest = ids.length - shown.length;
  return rest > 0
    ? `IDs: ${shown.join(", ")} (+${rest} dalších)`
    : `IDs: ${shown.join(", ")}`;
}

// ---------- load rows ----------
const rows = items.map(i => i.json);

// ---------- define previous local day window in Europe/Prague -----
const todayYMD = ymdInPrague(new Date());
const todayStartMs = makePragueMidnightMs(todayYMD);

// previous local midnight in Prague
const prevDayDate = new Date(todayStartMs - 1);
const prevYMD = ymdInPrague(prevDayDate);
const startMs = makePragueMidnightMs(prevYMD);
const endMs = todayStartMs;

const startStr = formatPrague(startMs);
const endStr   = formatPrague(endMs);

// ---------- filter + keep parsed ms ----------
const windowRows = [];
for (let i = 0; i < rows.length; i++) {
  const r = rows[i];
  const t = r[COL.time];
  if (!t) continue;
  const ms = toMs(t);
  if (ms === null) continue;
  if (ms >= startMs && ms < endMs) {
    windowRows.push({ r, ms });
  }
}

if (!windowRows.length) {
  return [{
    json: {
      ok: false,
      error: "No rows found in previous Prague-local day window",
      window: { start: startStr, end: endStr },
    }
  }];
}

windowRows.sort((a,b) => a.ms - b.ms);
const N = windowRows.length;

// ---------- accumulators ----------
const violatedTs = new Set();

const mmCellV = { min: Infinity, max: -Infinity };
const mmModV  = { min: Infinity, max: -Infinity };
const mmCellT = { min: Infinity, max: -Infinity };
const mmModT  = { min: Infinity, max: -Infinity };
const mmSoc   = { min: Infinity, max: -Infinity };

// tallies
const tCellMaxT = new Map();
const tCellMinT = new Map();
const tModMaxT  = new Map();
const tModMinT  = new Map();
const tCellMaxV = new Map();
const tCellMinV = new Map();
const tModMaxV  = new Map();
const tModMinV  = new Map();

// ---------- interval tracking ----------
const open = new Map();
const violationRanges = [];

function makeKey(metric, type) {
  return `${metric}::${type}`;
}

function addIdsFromDetailsToSet(set, details) {
  if (!set || !details) return;
  const idMax = details.idMax ?? null;
  const idMin = details.idMin ?? null;
  if (idMax !== null && idMax !== undefined && String(idMax).trim() !== "") set.add(String(idMax).trim());
  if (idMin !== null && idMin !== undefined && String(idMin).trim() !== "") set.add(String(idMin).trim());
}

function startRange(metric, type, rule, unit, t, ms, value, details) {
  const ids = new Set();
  addIdsFromDetailsToSet(ids, details);

  return {
    metric,
    type,
    rule,
    unit: unit || (rule && rule.unit) || null,

    startTime: t,
    startMs: ms,

    endTime: null,
    endMs: null,

    lastBadTime: t,
    lastBadMs: ms,

    points: 1,

    minValue: value,
    maxValue: value,

    worstValue: value,

    ids,

    openEnded: false,
    durationMs: null,
    duration: null,
  };
}

function updateRange(rg, ms, t, value, details, isBelowType) {
  rg.lastBadTime = t;
  rg.lastBadMs = ms;
  rg.points += 1;

  if (value !== null && value !== undefined) {
    if (rg.minValue === null || rg.minValue === undefined) rg.minValue = value;
    if (rg.maxValue === null || rg.maxValue === undefined) rg.maxValue = value;

    if (value < rg.minValue) rg.minValue = value;
    if (value > rg.maxValue) rg.maxValue = value;

    if (isBelowType) {
      if (rg.worstValue === null || value < rg.worstValue) rg.worstValue = value;
    } else {
      if (rg.worstValue === null || value > rg.worstValue) rg.worstValue = value;
    }
  }

  addIdsFromDetailsToSet(rg.ids, details);
}

function closeRange(key, resolvedTime, resolvedMs) {
  const rg = open.get(key);
  if (!rg) return;

  rg.endTime = resolvedTime;
  rg.endMs = resolvedMs;

  rg.durationMs = rg.endMs - rg.startMs;
  rg.duration = formatDuration(rg.durationMs);

  violationRanges.push(rg);
  open.delete(key);
}

function track(metric, type, isBad, t, ms, value, rule, unit, details) {
  const key = makeKey(metric, type);
  const isBelow = (type === "below_min");
  const isActive = open.has(key);

  if (isBad) {
    if (!isActive) {
      open.set(key, startRange(metric, type, rule, unit, t, ms, value, details));
    } else {
      updateRange(open.get(key), ms, t, value, details, isBelow);
    }
  } else {
    if (isActive) closeRange(key, t, ms);
  }
}

// ---------- single pass checks ----------
for (let i = 0; i < N; i++) {
  const row = windowRows[i].r;
  const ms = windowRows[i].ms;
  const t = row[COL.time];

  let anyBadThisRow = false;

  const cTmin = toNum(row[COL.cellTmin]);
  const cTmax = toNum(row[COL.cellTmax]);
  const mTmin = toNum(row[COL.modTmin]);
  const mTmax = toNum(row[COL.modTmax]);

  const cVmin = toNum(row[COL.cellVmin]);
  const cVmax = toNum(row[COL.cellVmax]);
  const mVmin = toNum(row[COL.modVmin]);
  const mVmax = toNum(row[COL.modVmax]);

  const s = toNum(row[COL.soc]);

  minMaxPush(mmCellV, cVmin); minMaxPush(mmCellV, cVmax);
  minMaxPush(mmModV,  mVmin); minMaxPush(mmModV,  mVmax);
  minMaxPush(mmCellT, cTmin); minMaxPush(mmCellT, cTmax);
  minMaxPush(mmModT,  mTmin); minMaxPush(mmModT,  mTmax);
  minMaxPush(mmSoc,   s);

  const cTminBad = (cTmin !== null && cTmin < LIMITS.cellTemp.min);
  const cTmaxBad = (cTmax !== null && cTmax > LIMITS.cellTemp.max);
  track("cell_temp_min", "below_min", cTminBad, t, ms, cTmin, LIMITS.cellTemp, "°C");
  track("cell_temp_max", "above_max", cTmaxBad, t, ms, cTmax, LIMITS.cellTemp, "°C");
  if (cTminBad || cTmaxBad) anyBadThisRow = true;

  const mTminBad = (mTmin !== null && mTmin < LIMITS.modTemp.min);
  const mTmaxBad = (mTmax !== null && mTmax > LIMITS.modTemp.max);
  track("module_temp_min", "below_min", mTminBad, t, ms, mTmin, LIMITS.modTemp, "°C");
  track("module_temp_max", "above_max", mTmaxBad, t, ms, mTmax, LIMITS.modTemp, "°C");
  if (mTminBad || mTmaxBad) anyBadThisRow = true;

  const socLow = (s !== null && s < LIMITS.soc.min);
  const socHigh = (s !== null && s > LIMITS.soc.max);
  track("soc", "below_min", socLow, t, ms, s, LIMITS.soc, "%");
  track("soc", "above_max", socHigh, t, ms, s, LIMITS.soc, "%");
  if (socLow || socHigh) anyBadThisRow = true;

  const cVminBad = (cVmin !== null && cVmin < LIMITS.cellVolt.min);
  const cVmaxBad = (cVmax !== null && cVmax > LIMITS.cellVolt.max);
  track("cell_voltage_min", "below_min", cVminBad, t, ms, cVmin, LIMITS.cellVolt, "V");
  track("cell_voltage_max", "above_max", cVmaxBad, t, ms, cVmax, LIMITS.cellVolt, "V");
  if (cVminBad || cVmaxBad) anyBadThisRow = true;

  if (cTmin !== null && cTmax !== null) {
    const spread = cTmax - cTmin;
    const bad = spread > LIMITS.cellTempSpreadMax;
    track(
      "cell_temp_spread",
      "spread_exceeded",
      bad,
      t,
      ms,
      spread,
      { max: LIMITS.cellTempSpreadMax, unit: "°C" },
      "°C",
      bad ? { idMax: row[COL.cellIdMaxT] ?? null, idMin: row[COL.cellIdMinT] ?? null } : null
    );
    if (bad) anyBadThisRow = true;
  } else {
    track("cell_temp_spread", "spread_exceeded", false, t, ms, null, { max: LIMITS.cellTempSpreadMax, unit: "°C" }, "°C");
  }

  if (mTmin !== null && mTmax !== null) {
    const spread = mTmax - mTmin;
    const bad = spread > LIMITS.modTempSpreadMax;
    track(
      "module_temp_spread",
      "spread_exceeded",
      bad,
      t,
      ms,
      spread,
      { max: LIMITS.modTempSpreadMax, unit: "°C" },
      "°C",
      bad ? { idMax: row[COL.modIdMaxT] ?? null, idMin: row[COL.modIdMinT] ?? null } : null
    );
    if (bad) anyBadThisRow = true;
  } else {
    track("module_temp_spread", "spread_exceeded", false, t, ms, null, { max: LIMITS.modTempSpreadMax, unit: "°C" }, "°C");
  }

  if (mVmin !== null && mVmax !== null) {
    const spread = mVmax - mVmin;
    const bad = spread > LIMITS.moduleVoltSpreadMax;
    track(
      "module_voltage_spread",
      "spread_exceeded",
      bad,
      t,
      ms,
      spread,
      { max: LIMITS.moduleVoltSpreadMax, unit: "V" },
      "V",
      bad ? { idMax: row[COL.modIdMaxV] ?? null, idMin: row[COL.modIdMinV] ?? null } : null
    );
    if (bad) anyBadThisRow = true;
  } else {
    track("module_voltage_spread", "spread_exceeded", false, t, ms, null, { max: LIMITS.moduleVoltSpreadMax, unit: "V" }, "V");
  }

  if (cVmin !== null && cVmax !== null) {
    const spread = cVmax - cVmin;
    const bad = spread > LIMITS.cellVoltSpreadMax;
    track(
      "cell_voltage_spread",
      "spread_exceeded",
      bad,
      t,
      ms,
      spread,
      { max: LIMITS.cellVoltSpreadMax, unit: "V" },
      "V",
      bad ? { idMax: row[COL.cellIdMaxV] ?? null, idMin: row[COL.cellIdMinV] ?? null } : null
    );
    if (bad) anyBadThisRow = true;
  } else {
    track("cell_voltage_spread", "spread_exceeded", false, t, ms, null, { max: LIMITS.cellVoltSpreadMax, unit: "V" }, "V");
  }

  if (anyBadThisRow) violatedTs.add(t);

  tallyInc(tCellMaxT, row[COL.cellIdMaxT]);
  tallyInc(tCellMinT, row[COL.cellIdMinT]);
  tallyInc(tModMaxT,  row[COL.modIdMaxT]);
  tallyInc(tModMinT,  row[COL.modIdMinT]);

  tallyInc(tCellMaxV, row[COL.cellIdMaxV]);
  tallyInc(tCellMinV, row[COL.cellIdMinV]);
  tallyInc(tModMaxV,  row[COL.modIdMaxV]);
  tallyInc(tModMinV,  row[COL.modIdMinV]);
}

// Close any still-open violations at window end
for (const [key, rg] of open.entries()) {
  rg.endTime = endStr;
  rg.endMs = endMs;
  rg.openEnded = true;
  rg.durationMs = rg.endMs - rg.startMs;
  rg.duration = formatDuration(rg.durationMs);
  violationRanges.push(rg);
}
open.clear();

function finalizeMM(mm) {
  if (mm.min === Infinity) return { min: null, max: null };
  return { min: mm.min, max: mm.max };
}

const top = {
  cell_max_temp: topShare(tCellMaxT),
  cell_min_temp: topShare(tCellMinT),
  mod_max_temp:  topShare(tModMaxT),
  mod_min_temp:  topShare(tModMinT),
  cell_max_volt: topShare(tCellMaxV),
  cell_min_volt: topShare(tCellMinV),
  mod_max_volt:  topShare(tModMaxV),
  mod_min_volt:  topShare(tModMinV),
};

const violationRangesOut = violationRanges.map(v => {
  const unit = v.unit || (v.rule && v.rule.unit) || null;
  const d = decimalsFor(unit, v.metric);

  const idsText = (v.type === "spread_exceeded" && v.ids && v.ids.size)
    ? fmtIds(Array.from(v.ids), 12)
    : "";

  return {
    metric: v.metric,
    type: v.type,

    startTime: v.startTime,
    endTime: v.endTime,
    openEnded: !!v.openEnded,
    duration: v.duration,
    points: v.points,

    unit,

    worstValue: roundTo(v.worstValue, d),
    minValue: roundTo(v.minValue, d),
    maxValue: roundTo(v.maxValue, d),

    worstText: `${fmtSmart(v.worstValue, unit, v.metric)}${unit ? " " + unit : ""}`.trim(),
    minText: fmtSmart(v.minValue, unit, v.metric),
    maxText: fmtSmart(v.maxValue, unit, v.metric),
    ruleText: fmtRule(v.rule, unit, v.metric),

    detailsText: idsText,
  };
});

const summary = {
  window: { start: startStr, end: endStr, points: N },

  cell_voltage:   { ...finalizeMM(mmCellV), unit: "V" },
  module_voltage: { ...finalizeMM(mmModV),  unit: "V" },
  cell_temp:      { ...finalizeMM(mmCellT), unit: "°C" },
  module_temp:    { ...finalizeMM(mmModT),  unit: "°C" },
  soc:            { ...finalizeMM(mmSoc),   unit: "%" },

  counts: {
    totalViolations: violationRangesOut.length,
    violatedTimestamps: violatedTs.size,
  }
};

return [{
  json: {
    ok: true,
    limits: LIMITS,
    summary,
    violationRanges: violationRangesOut,
    top,
  }
}];
